package com.google.gson.internal;

import java.lang.reflect.Type;
public final class Primitives{
public static boolean isWrapperType(Type type) {
    return type == Integer.class
        || type == Float.class
        || type == Byte.class
        || type == Double.class
        || type == Long.class
        || type == Character.class
        || type == Boolean.class
        || type == Short.class
        || type == Void.class;
  }
private  Primitives()
public static boolean isPrimitive(Type type)
@SuppressWarnings("unchecked") public static Class<T> wrap(Class<T> type)
@SuppressWarnings("unchecked") public static Class<T> unwrap(Class<T> type)
}
